window.NEXUS_CLIENTS =[
      {name:'Claudio',budget:'R$ 25.000',deadline:'90 dias',team:'1 PO, 2 devs, 1 UX parcial e 1 QA parcial',client:'PetVille',segment:'Petshop',difficulty:'Média',from:'Mariana Lima, proprietária da PetVille',subject:'Precisamos organizar os agendamentos do banho e tosa',briefing:'A PetVille é um petshop de bairro que cresceu rápido nos últimos meses. O principal problema é que muitos clientes esquecem o horário do banho e tosa, causando buracos na agenda, atrasos e perda de faturamento. Hoje os agendamentos ficam em um caderno na recepção e também em mensagens de WhatsApp. Uma funcionária tenta confirmar os horários manualmente, mas nem sempre consegue. A dona quer algo simples para organizar agenda, clientes, pets e confirmações. Ela comentou que gostaria de integração automática com WhatsApp no futuro, mas o orçamento atual não permite começar por algo muito complexo.',problem:'Faltas e confusão na agenda de banho e tosa geram perda de faturamento.',objective:'Planejar sistema web simples para agenda, clientes, pets e confirmação de horários.',restrictions:['Não desenvolver aplicativo mobile no MVP.','Integração automática com WhatsApp fica para evolução.','Equipe da recepção tem pouco tempo para treinamento.'],priorities:['Agenda de banho e tosa.','Cadastro de cliente e pet.','Confirmação de horário.'],risks:['Cliente pedir automações avançadas sem orçamento.','Recepção continuar usando caderno.','Dados antigos incompletos.'],tags:['Petshop','Agenda','MVP enxuto','WhatsApp futuro']},
      {name:'Nereyev',budget:'R$ 32.000',deadline:'75 dias',team:'1 analista, 2 devs e 1 QA parcial',client:'StrongFit Academia',segment:'Academia',difficulty:'Média',from:'Rafael Moura, proprietário da StrongFit',subject:'Controle de mensalidades e alunos',briefing:'A StrongFit possui cerca de 420 alunos ativos. O controle de mensalidades é feito em planilhas separadas por mês, e a recepção consulta pagamentos manualmente. Em horários de pico, formam-se filas porque os alunos querem saber vencimento, planos disponíveis e pendências. O proprietário deseja reduzir erros financeiros e quer relatórios simples de alunos ativos, inadimplentes e planos mais vendidos. Ele não quer contratar uma ferramenta mensal agora e prefere uma solução própria. Ainda não foram definidas regras claras de desconto, congelamento de plano e dependentes.',problem:'Controle manual de mensalidades gera filas, erros e dificuldade de acompanhar inadimplência.',objective:'Planejar sistema de alunos, planos, vencimentos, pagamentos e relatórios básicos.',restrictions:['Cliente não quer mensalidade de software.','Regras de desconto ainda não estão fechadas.','Não incluir catraca integrada no MVP.'],priorities:['Mensalidades.','Inadimplência.','Relatórios simples.'],risks:['Regras financeiras mudarem.','Recepção não alimentar dados corretamente.','Cliente pedir catraca ou app sem orçamento.'],tags:['Academia','Financeiro','Sem mensalidade','Relatórios']},
      {name:'Jose',budget:'R$ 18.000',deadline:'45 dias',team:'1 analista e 1 dev',client:'Restaurante Sabor Caseiro',segment:'Restaurante',difficulty:'Média',from:'Dona Celina, gerente do Sabor Caseiro',subject:'Pedidos estão se perdendo no horário de almoço',briefing:'O Restaurante Sabor Caseiro recebe pedidos pelo WhatsApp, telefone e balcão. Nos horários de almoço, os pedidos são anotados em papéis e repassados à cozinha. O problema é que pratos saem errados, pedidos se perdem e alguns clientes reclamam da demora. A dona quer visualizar pedidos em aberto, em preparo, prontos e entregues. Ela perguntou se seria possível criar um aplicativo para clientes, mas o orçamento e o prazo são curtos. A equipe da cozinha não tem muita familiaridade com computador, então a solução precisa ser objetiva.',problem:'Pedidos desorganizados causam erros, atrasos e reclamações.',objective:'Planejar painel simples de pedidos com status para cozinha e atendimento.',restrictions:['Aplicativo para cliente fica fora do MVP.','Prazo curto.','Equipe da cozinha precisa de interface simples.'],priorities:['Registro de pedido.','Status de preparo.','Comunicação entre atendimento e cozinha.'],risks:['Escopo crescer para delivery completo.','Equipe não atualizar status.','Pico de demanda no almoço.'],tags:['Restaurante','Pedidos','Prazo curto','Painel']},
      {name:'Ronnivon',budget:'R$ 28.000',deadline:'80 dias',team:'1 PO, 2 devs, 1 UX e 1 QA',client:'Clínica Vida Plena',segment:'Clínica médica',difficulty:'Alta',from:'Dra. Patrícia, diretora administrativa',subject:'Agenda da clínica está gerando conflitos',briefing:'A Clínica Vida Plena possui quatro médicos e duas recepcionistas. A agenda é compartilhada por planilha, mas frequentemente ocorrem conflitos de horários e encaixes sem registro. Pacientes ligam para confirmar consulta, mas a recepção perde tempo procurando informações. A direção quer reduzir faltas, organizar agendamentos e controlar status de atendimento. Existem dados sensíveis de pacientes, então segurança e acesso por perfil são importantes. A clínica pensa em teleatendimento no futuro, mas não quer isso no MVP.',problem:'Agenda descentralizada causa conflitos, faltas e lentidão no atendimento.',objective:'Planejar sistema de agenda médica, cadastro de pacientes, confirmações e controle de status.',restrictions:['Teleatendimento fica fora do MVP.','Controle de acesso é obrigatório.','Dados de saúde exigem cuidado e sigilo.'],priorities:['Agenda por profissional.','Confirmação de consulta.','Cadastro de pacientes.'],risks:['Dados sensíveis.','Conflito entre regras dos médicos.','Equipe pedir prontuário completo sem orçamento.'],tags:['Clínica','Agenda','Segurança','Pacientes']},
      {name:'Hudson',budget:'R$ 22.000',deadline:'60 dias',team:'1 analista, 2 devs e 1 QA parcial',client:'Loja Estilo Urbano',segment:'Loja de roupas',difficulty:'Média',from:'Amanda Reis, dona da Estilo Urbano',subject:'Estoque não bate com as vendas do Instagram',briefing:'A Loja Estilo Urbano vende presencialmente e pelo Instagram. O estoque é atualizado em caderno e planilhas, mas frequentemente há divergência entre o que aparece nas redes sociais e o que está disponível. Vendedores reservam peças por mensagem, mas esquecem de baixar do estoque. A dona quer visualizar estoque por tamanho, cor e categoria, além de registrar vendas básicas. Ela não precisa de e-commerce agora, mas quer preparar a loja para vender online no futuro. O orçamento não permite um projeto grande.',problem:'Controle manual de estoque gera divergência, reservas perdidas e vendas frustradas.',objective:'Planejar sistema simples de produtos, estoque, reservas e vendas básicas.',restrictions:['E-commerce fica para evolução.','Orçamento moderado.','Cadastro precisa ser rápido.'],priorities:['Estoque por variação.','Reserva de peças.','Registro de venda.'],risks:['Cadastro inicial trabalhoso.','Vendedores continuarem usando Instagram sem registrar.','Cliente pedir loja virtual no MVP.'],tags:['Estoque','Roupas','Instagram','Reservas']},
      {name:'Maycon',budget:'R$ 17.000',deadline:'50 dias',team:'1 analista, 1 dev e 1 QA parcial',client:'Oficina Roda Forte',segment:'Oficina mecânica',difficulty:'Alta',from:'Sérgio, dono da Oficina Roda Forte',subject:'Preciso localizar histórico dos veículos',briefing:'A Oficina Roda Forte registra serviços em fichas de papel. Quando um cliente retorna, a equipe não encontra rapidamente o histórico do veículo, peças trocadas ou orçamento anterior. A internet da oficina é instável e o ambiente de trabalho é corrido. O dono quer controlar ordens de serviço, clientes, veículos e status do serviço. Ele também gostaria de controlar estoque de peças, mas isso pode deixar o projeto maior do que o orçamento permite.',problem:'Histórico e ordens de serviço em papel dificultam atendimento e controle.',objective:'Planejar sistema de OS, clientes, veículos e histórico de manutenção.',restrictions:['Não incluir emissão fiscal.','Internet da oficina é instável.','Estoque completo fica para evolução.'],priorities:['Histórico por placa.','Status da OS.','Controle básico de serviços.'],risks:['Ambiente com pouca disciplina de registro.','Internet instável.','Cliente querer controle financeiro completo.'],tags:['Oficina','OS','Internet instável','Histórico']},
      {name:'Paulo Victor',budget:'R$ 26.000',deadline:'70 dias',team:'1 PO, 2 devs, 1 UX e 1 QA',client:'Escola Crescer',segment:'Escola particular',difficulty:'Média',from:'Direção da Escola Crescer',subject:'Comunicados aos responsáveis sem confirmação',briefing:'A Escola Crescer atende turmas do ensino fundamental. A direção relata dificuldade para comunicar avisos aos responsáveis. Hoje os comunicados são enviados por grupos de WhatsApp, mas muitos responsáveis não leem, outros respondem em conversas paralelas e a escola não consegue comprovar ciência. A direção quer organizar avisos por turma, responsável e aluno, com confirmação de leitura. Não deseja criar uma rede social escolar. Como envolve dados de menores, privacidade e controle de acesso são importantes.',problem:'Comunicação com responsáveis é desorganizada e sem confirmação de leitura.',objective:'Planejar plataforma de avisos, turmas, responsáveis e confirmações.',restrictions:['Não criar rede social escolar.','Responsáveis usam celulares diferentes.','Dados de menores exigem cuidado.'],priorities:['Comunicação por turma.','Confirmação de leitura.','Relatórios simples.'],risks:['Baixa adesão dos responsáveis.','Pedido de chat em tempo real.','Dados de menores de idade.'],tags:['Educação','Comunicação','Responsáveis','Privacidade']},
      {name:'Pedro Augusto',budget:'R$ 30.000',deadline:'85 dias',team:'1 analista, 3 devs, 1 QA e 1 designer parcial',client:'Hotel Boa Vista',segment:'Hotelaria',difficulty:'Alta',from:'Gerência do Hotel Boa Vista',subject:'Reservas duplicadas em datas movimentadas',briefing:'O Hotel Boa Vista controla reservas em agenda física e planilhas. Já ocorreram reservas duplicadas em datas movimentadas. A recepção precisa visualizar quartos disponíveis, ocupados, em limpeza e bloqueados. O gerente quer controlar check-in e check-out, mas relatórios financeiros podem ficar para depois. O hotel gostaria no futuro de integrar com plataformas como Booking e Airbnb, porém o orçamento atual não permite. A prioridade é evitar overbooking e organizar a operação diária da recepção.',problem:'Reservas manuais causam overbooking e falta de visão da ocupação.',objective:'Planejar sistema de reservas, ocupação de quartos, check-in, check-out e status de limpeza.',restrictions:['Sem integração com Booking/Airbnb no MVP.','Relatórios financeiros ficam para evolução.','Interface simples para recepção.'],priorities:['Reservas.','Disponibilidade de quartos.','Check-in e check-out.'],risks:['Overbooking durante implantação.','Resistência da equipe antiga.','Cliente insistir em integrações externas.'],tags:['Hotel','Reservas','Overbooking','Check-in']},
      {name:'João Pedro',budget:'R$ 16.000',deadline:'40 dias',team:'1 analista e 1 dev',client:'Barbearia Dom Corte',segment:'Barbearia',difficulty:'Média',from:'Bruno, proprietário da Barbearia Dom Corte',subject:'Agenda dos barbeiros está confusa',briefing:'A Barbearia Dom Corte possui três barbeiros e atende muitos clientes por indicação. Os horários são marcados por WhatsApp pessoal dos barbeiros, causando conflitos de agenda e clientes esquecidos. O dono quer uma solução simples para cadastro de clientes, agenda e histórico de serviços. O orçamento é baixo e o prazo é curto. Pagamento online e aplicativo próprio foram mencionados pelo cliente, mas não cabem no MVP. A solução precisa ser fácil de usar no celular.',problem:'Agendamentos por WhatsApp pessoal causam conflitos e perda de clientes.',objective:'Planejar solução simples de agendamento, cadastro de clientes e histórico de serviços.',restrictions:['Orçamento baixo.','Prazo curto.','Pagamento online fica fora do MVP.'],priorities:['Agenda simples.','Lembrete manual ou semi-automatizado.','Histórico de clientes.'],risks:['Cliente querer app próprio.','Barbeiros não registrarem atendimentos.','Agenda lotada aos finais de semana.'],tags:['Barbearia','Agenda','Baixo orçamento','Celular']},
      {name:'Ricardo',budget:'R$ 24.000',deadline:'65 dias',team:'1 PO, 2 devs e 1 QA',client:'ONG Mãos Unidas',segment:'ONG',difficulty:'Média',from:'Coordenação da ONG Mãos Unidas',subject:'Voluntários, campanhas e doações estão espalhados',briefing:'A ONG Mãos Unidas organiza campanhas de doação e ações sociais com voluntários. Hoje os dados ficam espalhados em planilhas, grupos de mensagem e cadernos. A coordenação não sabe com clareza quem participou de cada ação, quais doações chegaram e quais campanhas ainda precisam de apoio. A ONG não possui orçamento para ferramenta paga mensal e os usuários têm pouca experiência digital. O sistema precisa ser simples e ajudar na transparência das ações.',problem:'Dados de voluntários, doações e campanhas ficam dispersos.',objective:'Planejar sistema para voluntários, campanhas, doações e participação em ações.',restrictions:['Sem ferramenta paga mensal.','Usuários com pouca experiência digital.','Equipe voluntária tem horários limitados.'],priorities:['Cadastro de voluntários.','Controle de campanhas.','Registro de doações.'],risks:['Dados incompletos.','Mudança de responsáveis.','Dificuldade de uso por voluntários.'],tags:['ONG','Voluntários','Doações','Sem mensalidade']},
      {name:'Josue',budget:'R$ 21.000',deadline:'55 dias',team:'1 analista, 2 devs e 1 QA parcial',client:'Delivery Rápido Local',segment:'Delivery',difficulty:'Alta',from:'Márcio, gestor do Delivery Rápido Local',subject:'Pedidos e entregadores sem controle',briefing:'O Delivery Rápido Local atende pequenos restaurantes do bairro. Os pedidos chegam por WhatsApp e são repassados manualmente aos entregadores. O responsável não consegue saber em tempo real quais pedidos estão pendentes, em preparo, em rota ou entregues. Ele quer atribuir entregador, controlar status e confirmar entrega. O cliente perguntou sobre mapa e rastreamento, mas não há orçamento para geolocalização avançada neste momento. A solução precisa funcionar em notebook e celular.',problem:'Falta de controle dos pedidos e entregadores causa atrasos e reclamações.',objective:'Planejar painel de pedidos, status, entregadores e confirmação de entrega.',restrictions:['Sem rastreamento em tempo real no MVP.','Uso interno.','Precisa funcionar bem em celular e notebook.'],priorities:['Status dos pedidos.','Atribuição de entregador.','Confirmação de entrega.'],risks:['Cliente pedir geolocalização avançada.','Entregadores não atualizarem status.','Picos de demanda à noite.'],tags:['Delivery','Pedidos','Entregadores','Sem rastreamento']},
      {name:'Kaic',budget:'R$ 23.000',deadline:'60 dias',team:'1 analista, 2 devs, 1 UX parcial e 1 QA parcial',client:'Curso Livre Evoluir',segment:'Educação profissional',difficulty:'Média',from:'Larissa, coordenadora do Curso Evoluir',subject:'Matrículas, pagamentos e presença estão difíceis de acompanhar',briefing:'O Curso Livre Evoluir oferece turmas rápidas de informática, reforço escolar e qualificação profissional. As matrículas são feitas por formulário em papel, os pagamentos são controlados em planilhas e a presença é registrada em listas impressas. A coordenação perde muito tempo conferindo quem pagou, quem faltou e quem concluiu cada turma. Alguns alunos pedem declaração de participação, mas os dados ficam espalhados. A escola quer um sistema simples para cadastro de alunos, turmas, pagamentos, frequência e emissão de relatório básico. Certificados digitais automáticos podem ficar para uma etapa futura.',problem:'Controle manual de matrículas, pagamentos e frequência gera retrabalho e falhas de acompanhamento.',objective:'Planejar sistema para alunos, turmas, pagamentos, frequência e relatórios básicos.',restrictions:['Certificado digital automático fica fora do MVP.','Equipe administrativa pequena.','Precisa funcionar bem em computador comum.'],priorities:['Cadastro de alunos.','Controle de turmas.','Pagamentos e frequência.'],risks:['Dados antigos incompletos.','Cliente pedir portal do aluno no MVP.','Equipe esquecer de registrar frequência.'],tags:['Curso livre','Matrícula','Frequência','Pagamentos']},
      {name:'Emerson',budget:'R$ 27.000',deadline:'70 dias',team:'1 PO, 2 devs, 1 QA e 1 suporte parcial',client:'Contábil Prime',segment:'Escritório contábil',difficulty:'Alta',from:'Sócio da Contábil Prime',subject:'Documentos de clientes estão se perdendo',briefing:'O Escritório Contábil Prime recebe documentos de clientes por WhatsApp, e-mail e pendrive. Alguns arquivos se perdem, chegam fora do prazo ou são enviados para pessoas erradas. A equipe perde tempo cobrando documentos e organizando pastas. O sócio quer um portal simples para envio de documentos por cliente e competência mensal, com status de pendência, recebido e validado. Como há documentos sensíveis, segurança e controle de acesso são prioridade. Assinatura digital não entra no MVP.',problem:'Documentos contábeis espalhados causam perda de arquivos, retrabalho e risco de segurança.',objective:'Planejar portal para envio, organização e acompanhamento de documentos por cliente.',restrictions:['Sem assinatura digital no MVP.','Controle de acesso obrigatório.','Usuários externos com pouca familiaridade.'],priorities:['Upload de documentos.','Status por cliente.','Organização por mês/competência.'],risks:['Documentos sensíveis.','Clientes continuarem usando WhatsApp.','Falhas de permissão.'],tags:['Contabilidade','Documentos','Segurança','Portal']},
      {name:'Marimar',budget:'R$ 19.000',deadline:'50 dias',team:'1 analista, 1 dev e 1 designer parcial',client:'Agência Viajar Mais',segment:'Turismo',difficulty:'Média',from:'Rita, gerente da Agência Viajar Mais',subject:'Pacotes e pagamentos estão difíceis de acompanhar',briefing:'A Agência Viajar Mais organiza pacotes de viagens para grupos. As informações de clientes, pagamentos, datas, hotéis e passeios ficam em planilhas separadas. Quando um fornecedor muda data ou valor, a equipe demora para atualizar tudo. A agência quer acompanhar pacotes, status de pagamento e datas importantes por cliente. Não precisa vender online agora. O sistema deve ser visual e simples porque a equipe é pequena e trabalha com muitos contatos pelo WhatsApp.',problem:'Pacotes, pagamentos e datas ficam dispersos, gerando risco de erro com clientes.',objective:'Planejar sistema de acompanhamento de pacotes, clientes, pagamentos e datas importantes.',restrictions:['Sem venda online no MVP.','Equipe pequena.','Visualização simples por cliente e viagem.'],priorities:['Controle de pacotes.','Status de pagamento.','Datas importantes.'],risks:['Mudanças de datas por fornecedores.','Pedido de contrato automático.','Planilhas antigas desorganizadas.'],tags:['Turismo','Pacotes','Pagamentos','Datas']},
      {name:'Caio',budget:'R$ 34.000',deadline:'95 dias',team:'1 PO, 3 devs, 1 UX, 1 QA e 1 suporte parcial',client:'Assistência Técnica TechFix',segment:'Assistência técnica',difficulty:'Alta',from:'Henrique, proprietário da TechFix',subject:'Clientes ligam toda hora perguntando status do conserto',briefing:'A TechFix recebe celulares, notebooks e impressoras para manutenção. O atendimento abre ordens de serviço em fichas de papel, e os clientes ligam várias vezes para saber status. A empresa também perde controle de orçamento aprovado, peças utilizadas e histórico por cliente. O dono quer organizar atendimento, orçamento, status de reparo e histórico. Consulta de status pelo cliente seria interessante, mas pode ficar para evolução. Controle de estoque completo também não entra no MVP.',problem:'Ordens de serviço em papel dificultam status, orçamento, peças e histórico.',objective:'Planejar sistema de OS, orçamento, status de reparo e histórico de atendimento.',restrictions:['Sem estoque completo no MVP.','Consulta pública de status fica para evolução.','Tela simples para atendimento.'],priorities:['Ordem de serviço.','Status do reparo.','Aprovação de orçamento.'],risks:['Escopo crescer para estoque completo.','Clientes cobrarem status em tempo real.','Dados antigos desorganizados.'],tags:['Assistência técnica','OS','Orçamento','Status']},
      {name:'Maria Francisca',budget:'R$ 20.000',deadline:'58 dias',team:'1 analista, 1 dev, 1 UX parcial e 1 QA parcial',client:'Farmácia Popular São Lucas',segment:'Farmácia',difficulty:'Média',from:'Ana Paula, gerente da Farmácia São Lucas',subject:'Entregas e pedidos por WhatsApp estão desorganizados',briefing:'A Farmácia Popular São Lucas recebe muitos pedidos por WhatsApp, principalmente de clientes idosos e famílias do bairro. Os atendentes anotam os pedidos em papel, conferem estoque manualmente e depois repassam para o entregador. O problema é que alguns pedidos atrasam, outros saem incompletos e às vezes ninguém sabe se a entrega foi concluída. A gerente quer controlar pedido, separação, saída para entrega e confirmação de recebimento. Ela também gostaria de lembrar clientes sobre medicamentos recorrentes no futuro, mas isso não deve entrar na primeira versão. A farmácia precisa de algo simples e com controle de acesso para os atendentes.',problem:'Pedidos e entregas por WhatsApp ficam desorganizados, causando atrasos e falhas.',objective:'Planejar sistema interno para pedidos, separação, entregas e confirmação de recebimento.',restrictions:['Lembretes automáticos de medicamento ficam para evolução.','Controle de acesso para atendentes é necessário.','Sistema deve ser simples para uso durante atendimento.'],priorities:['Registro de pedidos.','Status de separação e entrega.','Confirmação de recebimento.'],risks:['Pedidos com dados sensíveis.','Atendentes continuarem usando papel.','Cliente pedir automação de WhatsApp sem orçamento.'],tags:['Farmácia','Entregas','Pedidos','Controle de acesso']}
    ];

window.NEXUS_SECOND_EMAILS = {
      'Claudio': {from:'Mariana Lima, proprietária da PetVille', subject:'Mais detalhes sobre a rotina da recepção', body:'Bom dia, equipe. Lembrei de alguns pontos importantes. Temos três atendentes, mas apenas uma pessoa costuma ficar responsável pela agenda. Aos sábados, a demanda dobra e é quando mais ocorrem faltas e encaixes. Muitos clientes têm mais de um pet, então às vezes um único cliente ocupa dois ou três horários. Hoje não temos uma lista confiável de quem faltou mais vezes. Também preciso que a solução seja simples, porque não posso parar a recepção por muitos dias para treinamento. Antes de pensarem em sistema, preciso que entendam esse fluxo.', attachments:['agenda-sabado.pdf','lista-clientes-recorrentes.xlsx']},
      'Nereyev': {from:'Rafael Moura, proprietário da StrongFit', subject:'Regras de planos e dificuldades da recepção', body:'Olá, consultor. Conversei com a recepção e percebi que o problema não é só saber quem pagou. Temos plano mensal, trimestral e semestral. Alguns alunos pagam em dinheiro, outros no Pix. Também existem alunos que congelam o plano por viagem ou problema de saúde, mas isso não está padronizado. A recepção anota observações em campos diferentes da planilha. O que mais me preocupa é a inadimplência, mas também quero evitar constrangimento na entrada da academia. Precisamos de organização antes de qualquer automação.', attachments:['modelo-planilha-mensalidades.xlsx','regras-planos.txt']},
      'Jose': {from:'Dona Celina, gerente do Sabor Caseiro', subject:'Fluxo real dos pedidos no almoço', body:'Bom dia. Falei com a equipe e descobri que os pedidos se perdem principalmente entre 11h30 e 13h30. O atendente recebe pelo WhatsApp, grita para a cozinha ou anota em papel. Às vezes falta endereço, às vezes falta forma de pagamento, e às vezes o cliente altera algo depois do pedido já estar na cozinha. Não queremos aplicativo agora. Queremos primeiro saber o que está pendente, o que está em preparo e o que já saiu. A cozinha precisa de uma tela muito simples.', attachments:['cardapio-resumido.pdf','fluxo-pedidos-atual.png']},
      'Ronnivon': {from:'Dra. Patrícia, diretora administrativa', subject:'Informações sobre agenda e acesso aos dados', body:'Olá. Antes de avançarmos, preciso reforçar que não queremos prontuário completo agora. O problema principal é agenda. Cada médico tem horários diferentes, alguns aceitam encaixe e outros não. As recepcionistas precisam ver rapidamente quem está confirmado, quem faltou e quem já foi atendido. Também precisamos evitar que qualquer funcionário acesse todos os dados dos pacientes. O sistema precisa respeitar perfis de acesso e registrar mudanças importantes.', attachments:['horarios-medicos.pdf','politica-acesso-clinica.docx']},
      'Hudson': {from:'Amanda Reis, dona da Estilo Urbano', subject:'Reservas pelo Instagram e variações dos produtos', body:'Oi. Percebi que esqueci de explicar uma coisa: vendemos muitas peças com variação de tamanho e cor. Às vezes uma blusa P está disponível, mas a M acabou. O problema no Instagram é que a vendedora reserva no direct e esquece de baixar no controle. Também temos peças que ficam separadas por até 24 horas esperando pagamento. Não quero loja virtual agora, mas quero parar de vender peça que não existe mais no estoque.', attachments:['categorias-produtos.xlsx','exemplo-reserva-instagram.png']},
      'Maycon': {from:'Sérgio, dono da Oficina Roda Forte', subject:'Como uma ordem de serviço acontece hoje', body:'Bom dia. Hoje quando o cliente chega, anotamos nome, telefone, placa e problema relatado. Depois o mecânico avalia e passa um orçamento. Muitas vezes o cliente só aprova no dia seguinte. O status pode ser: aguardando avaliação, aguardando aprovação, em manutenção, aguardando peça ou finalizado. A internet cai às vezes, então precisamos pensar em algo que não trave a oficina. O controle de peças é importante, mas pode ficar para outra fase.', attachments:['ficha-os-papel.pdf','status-servicos.txt']},
      'Paulo Victor': {from:'Direção da Escola Crescer', subject:'Comunicados críticos e confirmação dos responsáveis', body:'Olá. A maior dor acontece com avisos importantes, como reunião, prova, falta de professor e autorização de passeio. Alguns responsáveis dizem que não receberam, outros recebem em grupo errado. Não queremos chat aberto porque isso pode virar confusão. Precisamos enviar comunicado por turma e saber quem leu. A coordenação também quer emitir uma lista simples de pendentes. Lembre que lidamos com dados de alunos menores de idade.', attachments:['tipos-comunicados.pdf','turmas-exemplo.xlsx']},
      'Pedro Augusto': {from:'Gerência do Hotel Boa Vista', subject:'Detalhes sobre reservas e status dos quartos', body:'Prezados. A recepção trabalha com 18 quartos. Cada quarto pode estar disponível, ocupado, reservado, em limpeza ou bloqueado para manutenção. O maior problema é quando a reserva é feita por telefone e alguém esquece de atualizar a planilha. Não precisamos de integração com plataformas externas agora, mas precisamos evitar reserva duplicada. O check-in e o check-out devem ser simples. A equipe da limpeza também precisa informar quando um quarto foi liberado.', attachments:['mapa-quartos.pdf','planilha-reservas-exemplo.xlsx']},
      'João Pedro': {from:'Bruno, proprietário da Barbearia Dom Corte', subject:'Agenda por barbeiro e clientes recorrentes', body:'Fala, equipe. Cada barbeiro controla alguns horários pelo próprio WhatsApp, e aí acontecem conflitos. Temos clientes recorrentes que cortam cabelo toda semana ou a cada quinze dias. Seria bom saber o histórico do cliente, mas não quero nada complicado. Se tiver que instalar aplicativo, a equipe vai resistir. Quero algo simples, que funcione bem no celular e ajude a ver agenda por barbeiro.', attachments:['servicos-barbearia.pdf','agenda-manual-foto.png']},
      'Ricardo': {from:'Coordenação da ONG Mãos Unidas', subject:'Campanhas, voluntários e prestação de contas', body:'Olá. Nossas campanhas mudam bastante. Às vezes arrecadamos alimentos, às vezes roupas, às vezes material escolar. O problema é que não sabemos rapidamente quem doou, quem participou e o que ainda falta. Também precisamos prestar contas para parceiros, mas não temos relatório organizado. Como somos ONG, não podemos assumir custo mensal alto. Muitos voluntários usam apenas celular.', attachments:['campanhas-ativas.xlsx','modelo-prestacao-contas.pdf']},
      'Josue': {from:'Márcio, gestor do Delivery Rápido Local', subject:'Status dos pedidos e rotina dos entregadores', body:'Bom dia. Os entregadores trabalham por turno e alguns usam moto própria. O pedido passa por recebido, em preparo, pronto para coleta, em rota e entregue. O maior problema é que ninguém sabe onde cada pedido está, e o cliente fica perguntando. Não precisamos de mapa agora, mas precisamos atribuir entregador e registrar confirmação de entrega. À noite o volume aumenta muito.', attachments:['status-pedidos.txt','turnos-entregadores.xlsx']},
      'Kaic': {from:'Larissa, coordenadora do Curso Evoluir', subject:'Turmas, pagamentos e declarações dos alunos', body:'Olá. Temos turmas pequenas, mas muitas começam e terminam em datas diferentes. O pagamento pode ser à vista ou parcelado. A frequência é importante porque alguns alunos pedem declaração no final. Hoje fica difícil saber quem concluiu, quem faltou demais e quem ainda deve parcela. Não precisamos de certificado digital automático agora. Primeiro precisamos organizar aluno, turma, pagamento e presença.', attachments:['turmas-exemplo.xlsx','lista-presenca.pdf']},
      'Emerson': {from:'Sócio da Contábil Prime', subject:'Tipos de documentos e prazos mensais', body:'Prezados. Os documentos chegam principalmente entre os dias 1 e 10 de cada mês. Cada cliente envia notas, extratos, comprovantes e folha de pagamento. O problema é que os arquivos chegam por vários canais e ninguém sabe o que ainda está pendente. Precisamos controlar documento por cliente e por competência mensal. Segurança é essencial, pois um cliente não pode acessar documentos de outro.', attachments:['tipos-documentos.pdf','competencia-mensal.xlsx']},
      'Marimar': {from:'Rita, gerente da Agência Viajar Mais', subject:'Atualizações de fornecedores e controle de pagamentos', body:'Olá. Os pacotes dependem de hotéis, empresas de ônibus e passeios. Quando um fornecedor muda valor ou data, precisamos atualizar todos os clientes daquele pacote. O controle de pagamento também é confuso, pois alguns pagam entrada e parcelam o restante. Não quero venda online agora. Quero acompanhar pacote, cliente, datas e pagamento sem depender de várias planilhas.', attachments:['pacotes-ativos.xlsx','fornecedores.pdf']},
      'Caio': {from:'Henrique, proprietário da TechFix', subject:'Status de reparo e aprovação de orçamento', body:'Bom dia. Quando o aparelho chega, abrimos uma ficha, avaliamos o defeito e depois enviamos orçamento para aprovação. Muitos clientes ligam perguntando se já avaliou, se aprovou, se a peça chegou ou se ficou pronto. Os status principais são: recebido, em diagnóstico, aguardando aprovação, aguardando peça, em reparo e finalizado. Consulta pública pode ficar para depois, mas internamente precisamos controlar melhor.', attachments:['ficha-atendimento.pdf','status-reparo.txt']},
      'Maria Francisca': {from:'Ana Paula, gerente da Farmácia São Lucas', subject:'Pedidos recorrentes e confirmação de entrega', body:'Olá. Alguns clientes pedem os mesmos medicamentos todo mês, mas não queremos automatizar lembretes agora. O problema imediato é saber se o pedido foi separado, saiu para entrega e foi recebido. Também precisamos registrar quem atendeu e quem entregou. Como lidamos com dados sensíveis, não quero que qualquer pessoa veja tudo. O sistema precisa ser simples, porque o atendimento não pode parar.', attachments:['fluxo-entrega.pdf','tipos-pedido.xlsx']}
    };

