    function el(id){return document.getElementById(id)}
    document.querySelectorAll('nav button').forEach(btn=>btn.addEventListener('click',()=>{document.querySelectorAll('nav button').forEach(b=>b.classList.remove('active'));document.querySelectorAll('.tab-panel').forEach(p=>p.classList.remove('active'));btn.classList.add('active');el(btn.dataset.tab).classList.add('active');window.scrollTo({top:0,behavior:'smooth'})}));

    const current=sprints[currentSprintIndex];
    el('dashboardMetrics').innerHTML=`<div class="metric"><small>Sprint atual</small><strong>${current.day}</strong></div><div class="metric"><small>Status</small><strong>${current.status}</strong></div><div class="metric"><small>XP</small><strong>${current.xp}</strong></div><div class="metric"><small>Recompensa</small><strong>${current.coins}</strong></div><div class="metric"><small>Entrega</small><strong>Teams</strong></div>`;
    el('currentGoal').textContent=current.goal;
    el('currentDelivery').textContent=current.output;
    el('timeline').innerHTML=sprints.map((s,i)=>`<div class="timeline-item ${i===currentSprintIndex?'active':'locked'}"><strong>${String(i+1).padStart(2,'0')}</strong><span>${s.phase}</span></div>`).join('');

    el('sprintCards').innerHTML=sprints.map((s,i)=>`<details ${i===0?'open':''}><summary class="sprint-summary"><span class="name">${s.day}</span><span class="title">${s.title}</span><span class="budget purple">${s.xp}</span></summary><div class="detail-body"><div class="tags"><span class="pill go">${s.phase}</span><span class="pill blue">${s.status}</span><span class="pill">${s.time}</span><span class="pill hot">${s.coins}</span></div><div class="highlight success"><strong>Sprint Goal:</strong> ${s.goal}</div><p><strong>Contexto:</strong> ${s.context}</p><p><strong>Demanda:</strong> ${s.demand}</p><p><strong>Entrega oficial no Teams:</strong> ${s.output}</p><div class="sprint-grid"><div class="card"><h3>Checklist da Sprint</h3><div class="checklist">${s.checklist.map(c=>`<div class="check"><span class="box"></span><span>${c}</span></div>`).join('')}</div></div><div class="card"><h3>Definition of Done</h3><ul>${s.dod.map(d=>`<li>${d}</li>`).join('')}</ul><h3>Critérios de Aceite</h3><ul>${s.acceptance.map(a=>`<li>${a}</li>`).join('')}</ul></div></div><div class="grid2"><div class="card"><h3>Ferramentas sugeridas</h3><div class="tools">${s.tools.map(t=>`<span>${t}</span>`).join('')}</div></div><div class="card"><h3>Competências desenvolvidas</h3><div class="tools">${s.competencies.map(t=>`<span>${t}</span>`).join('')}</div></div></div></div></details>`).join('');